widget_code.css:
.cwk-animated-border-three .elementor-button {
  color: #435a6b;
}
.cwk-animated-border-three .elementor-button::after, 
.cwk-animated-border-three .elementor-button::before {
  content: "";
  display: block;
  position: absolute;
  width: 20%;
  height: 20%;
  border: 2px solid;
  transition: all 0.6s ease;
  border-radius: 2px;
}
.cwk-animated-border-three .elementor-button::after {
  bottom: 0;
  right: 0;
  border-top-color: transparent;
  border-left-color: transparent;
  border-bottom-color: #435a6b;
  border-right-color: #435a6b;
}
.cwk-animated-border-three .elementor-button::before {
  top: 0;
  left: 0;
  border-bottom-color: transparent;
  border-right-color: transparent;
  border-top-color: #435a6b;
  border-left-color: #435a6b;
}
.cwk-animated-border-three .elementor-button:hover:after, 
.cwk-animated-border-three .elementor-button:hover:before {
  border-bottom-color: #435a6b;
  border-right-color: #435a6b;
  border-top-color: #435a6b;
  border-left-color: #435a6b;
  width: 100%;
  height: 100%;
}
